14	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	};
21	
22	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
23	const PROCESSING_FEE = 5;
24	
25	function quoteStep(step: QuoteStep) {
26	  const basePremium = BASE_PREMIUM_BY_ITEM[step.items[0].kind];
27	  const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
28	  const premium = Math.ceil(basePremium + surcharge + PROCESSING_FEE);
29	  return { kind: "quote" as const, premium };
30	}
31	
32	export function processScenario(scenario: Scenario): ScenarioResult {
33	  const results = scenario.steps.map(quoteStep);
34	  return { results };
35	}
